#include <iostream>

template <typename T>
const T& larger(const T& left, const T& right) {
    return right < left ? left : right;
}

int main() {
    int a{}, b{}, c{};
    if (!(std::cin >> a >> b >> c)) return 1;
    std::cout << larger(larger(a, b), c) << '\n';
}
